mapper.select:
SELECT c.no, c.board_no, b.title AS board_title, c.member_no, c.content, TO_CHAR(c.regdate,'YYYY-MM-DD HH24:MI') AS reg_date, c.is_deleted, m.name, m.member_id FROM board_comment c JOIN board b ON c.board_no = b.no JOIN member m ON c.member_no = m.no WHERE b.board_type = 'REVIEW'
AND c.is_deleted = #{searchDeleted}
AND c.content LIKE '%' || #{keyword} || '%'
AND m.member_id = #{keyword}
ORDER BY c.no DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(*) FROM board_comment c JOIN board b ON c.board_no = b.no JOIN member m ON c.member_no = m.no WHERE b.board_type = 'REVIEW'
AND c.is_deleted = #{searchDeleted}
AND c.content LIKE '%' || #{keyword} || '%'
AND m.member_id = #{keyword}
